const item = $('Teacher AI').first().json.output;


return [{
  json: {
    title: item.title || 'Untitled',
    keyPoints: item.keyPoints || [],
    mainConcepts: item.mainConcepts || [],
    difficulty: item.difficulty || 'intermediate',
    url: $('Extract URL').first().json.url || '',
    chatId: $('Extract URL').first().json.chatId
  }
}];

const item = $input.first();
const title = item.json.title || 'Untitled';
const keyPoints = item.json.keyPoints || [];
const mainConcepts = item.json.mainConcepts || [];
const difficulty = item.json.difficulty || 'intermediate';
const url = item.json.url || '';

let message = `📚 <b>${title}</b>\n\n`;
message += `🎯 <b>Difficulty:</b> ${difficulty.charAt(0).toUpperCase() + difficulty.slice(1)}\n\n`;
message += `<b>Key Points:</b>\n`;
keyPoints.forEach((point, index) => {
  message += `${index + 1}. ${point}\n`;
});
message += `\n<b>Main Concepts:</b>\n`;
message += mainConcepts.join(', ');
message += `\n\n🔗 <a href="${url}">View Original</a>`;

return [{ json: { ...item.json, formattedMessage: message } }];

