parameters.jsCode:
const questions = $input.first().json.data;
const userAnswers = $('Read Quiz State').first().json.answers;

// Calculate score
let correctCount = 0;
const results = [];

for (let i = 0; i < questions.length; i++) {
  const question = questions[i];
  const userAnswer = userAnswers[i];
  const isCorrect = userAnswer === question.correctAnswer;

  if (isCorrect) {
    correctCount++;
  }

  results.push({
    question: question.question,
    userAnswer: userAnswer,
    correctAnswer: question.correctAnswer,
    isCorrect: isCorrect,
    explanation: question.Explanation
  });
}

const percentage = Math.round((correctCount / questions.length) * 100);

// Build results message
let message = '🎓 Quiz Results\n\n';
message += '📊 Your score: ' + correctCount + '/5 (' + percentage + '%)\n\n';

for (let i = 0; i < results.length; i++) {
  const result = results[i];
  const emoji = result.isCorrect ? '✅' : '❌';
  message += (i + 1) + '. ' + emoji + ' ' + result.question + '\n';

  if (!result.isCorrect) {
    message += '   Correct answer: ' + result.correctAnswer + '\n';
    message += '   Explanation: ' + result.explanation + '\n';
  }
  message += '\n';
}

return {
  json: {
    score: correctCount,
    total: questions.length,
    percentage: percentage,
    message: message
  }
};

const html = $input.first().json.data;

const clean = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/\s+/g, ' ')
  .trim();

const words = clean.split(' ').slice(0, 100000).join(' ');

return [{ json: { text: words } }];

const items = $input.all();

return items.map(item => {
  const fields = ["keyPoints", "mainConcepts"]
  fields.forEach(field => {
    const raw = item.json[field];

    if (Array.isArray(raw)) {
      item.json[field] = raw.join(", ");
    } else if (typeof raw === "string" && raw.startsWith("[")) {
      item.json[field] = JSON.parse(raw).join(", ");
    }
  });

  return item;
});
